1	'use client';
2	
3	import { useEffect, useState } from 'react';
4	import { Paperclip, X } from 'lucide-react';
5	import { Button } from '@/components/ui/button';
6	import { Input } from '@/components/ui/input';
7	
8	type UploadedMessage = {
9	  id: string;
10	  channelId: string;
11	  employeeId: string | null;
12	  role: 'user' | 'assistant' | 'system';
13	  content: string;
14	  createdAt: string;
15	  authorName: string | null;
16	};
17	
18	export function DocumentUpload({
19	  channelId,
20	  employeeId: _employeeId,
21	  initialFile,
22	  onDone,
23	}: {
24	  channelId: string;
25	  employeeId: string;
26	  /** Pre-populate the file (e.g. from a drag-and-drop). */
27	  initialFile?: File | null;
28	  onDone: (message: UploadedMessage | null) => void;
29	}) {
30	  const [file, setFile] = useState<File | null>(initialFile ?? null);
31	  const [caption, setCaption] = useState('');
32	  const [status, setStatus] = useState<'idle' | 'uploading' | 'done' | 'error'>('idle');
33	  const [errorMsg, setErrorMsg] = useState<string | null>(null);
34	
35	  // Sync when a file is dropped externally (drag-to-upload from parent).
36	  useEffect(() => {
37	    if (initialFile) {
38	      const id = window.setTimeout(() => {
39	        setFile(initialFile);
40	        setStatus('idle');
41	        setErrorMsg(null);
42	      }, 0);
43	      return () => window.clearTimeout(id);
44	    }
45	    return undefined;
46	  }, [initialFile]);
47	
48	  async function upload() {
49	    if (!file) return;
50	    setStatus('uploading');
51	    setErrorMsg(null);
52	
53	    try {
54	      const body = new FormData();
55	      body.append('file', file);
56	      body.append('channelId', channelId);
57	      if (caption.trim()) body.append('caption', caption.trim());
58	
59	      const res = await fetch('/api/documents', {
60	        method: 'POST',
61	        body,
62	        // Do NOT set Content-Type — browser adds the multipart boundary.
63	      });
64	
65	      if (!res.ok) {
66	        const errBody = await res.text();
67	        console.error('[upload] /api/documents failed', res.status, errBody);
68	        throw new Error(`Upload failed (${res.status}): ${errBody}`);
69	      }
70	
71	      const data = (await res.json()) as {
72	        ok: boolean;
73	        documentId: string;
74	        storagePath: string;
75	        message: UploadedMessage | null;
76	      };
77	
78	      setStatus('done');
79	      onDone(data.message);
80	    } catch (err) {
81	      console.error('[upload] failed', err);
82	      setStatus('error');
83	      setErrorMsg(err instanceof Error ? err.message : 'Upload failed.');
84	    }
85	  }
86	
87	  function clearFile() {
88	    setFile(null);
89	    setCaption('');
90	    setStatus('idle');
91	    setErrorMsg(null);
92	  }
93	
94	  return (
95	    <div className="space-y-2">
96	      {/* File picker row */}
97	      <div className="flex items-center gap-2">
98	        {file ? (
99	          <div className="flex flex-1 items-center gap-2 rounded-md border bg-muted/40 px-3 py-2 text-sm">
100	            <Paperclip className="size-4 shrink-0 text-muted-foreground" />
101	            <span className="flex-1 truncate text-foreground">{file.name}</span>
102	            <span className="shrink-0 text-xs text-muted-foreground">
103	              {(file.size / 1024).toFixed(0)} KB
104	            </span>
105	            <button
106	              type="button"
107	              onClick={clearFile}
108	              className="shrink-0 text-muted-foreground hover:text-foreground"
109	              aria-label="Remove file"
110	            >
111	              <X className="size-4" />
112	            </button>
113	          </div>
114	        ) : (
115	          <label className="flex-1 cursor-pointer">
116	            <div className="flex items-center gap-2 rounded-md border border-dashed bg-background px-3 py-2 text-sm text-muted-foreground hover:border-ring hover:text-foreground">
117	              <Paperclip className="size-4 shrink-0" />
118	              <span>Choose a file…</span>
119	            </div>
120	            <input
121	              type="file"
122	              className="sr-only"
123	              disabled={status === 'uploading'}
124	              onChange={(e) => {
125	                const f = e.target.files?.[0] ?? null;
126	                setFile(f);
127	                setStatus('idle');
128	                setErrorMsg(null);
129	                // Reset input so the same file can be reselected after clear.
130	                e.target.value = '';
131	              }}
132	            />
133	          </label>
134	        )}
135	
136	        <Button
137	          type="button"
138	          size="sm"
139	          onClick={upload}
140	          disabled={!file || status === 'uploading'}
141	        >
142	          {status === 'uploading' ? 'Sending…' : 'Send'}
143	        </Button>
144	      </div>
145	
146	      {/* Caption / question */}
147	      {file && (
148	        <Input
149	          value={caption}
150	          onChange={(e) => setCaption(e.target.value)}
151	          placeholder="Add a message or question about this file… (optional)"
152	          disabled={status === 'uploading'}
153	          onKeyDown={(e) => {
154	            if (e.key === 'Enter' && !e.shiftKey && file && status !== 'uploading') {
155	              e.preventDefault();
156	              void upload();
157	            }
158	          }}
159	        />
160	      )}
161	
162	      {file && file.type.startsWith('image/') && status === 'idle' && (
163	        <p className="text-xs text-amber-600">
164	          Tip: add a caption so Oracle knows what to look for in this image.
165	          If Oracle says it can&apos;t see the image, use the main text box to
166	          describe it after uploading.
167	        </p>
168	      )}
169	      {status === 'done' && (
170	        <p className="text-xs text-green-600">Sent.</p>
171	      )}
172	      {errorMsg && (
173	        <p className="text-xs text-destructive">{errorMsg}</p>
174	      )}
175	    </div>
176	  );
177	}
