1	// R7 — Document ingestion worker (refactored through OracleAIClient + staging).
2	//
3	// Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R7.
4	//
5	// What changed vs the legacy worker:
6	//   - Model calls go through OracleAIClient (R2) via direct provider adapters
7	//     (Vertex / Anthropic / OpenAI raw SDKs — DECISIONS.md D6 / D9) using
8	//     the curated route ID from `settings.default_extraction_route`. R7
9	//     ships the explicit-cache profitability heuristic +
10	//     provider_cached_content lifecycle bookkeeping; native Vertex
11	//     cachedContent lifecycle creation is a round-2 follow-up to R-providers.
12	//   - Output flows through extraction_batches → extraction_candidates →
13	//     extraction_candidate_evidence first. NOTHING writes to permanent
14	//     claims tables before R5's deterministic validator passes.
15	//   - Per-claim quote validation against the matching document_chunk's text
16	//     (not the full document).
17	//   - Per-claim taxonomy validation against active knowledge_top_domains.
18	//   - Race-safe promotion via executePromotion (snapshotInputs path) —
19	//     uses claims.candidate_hash to detect historical duplicates across
20	//     ingestion runs.
21	//   - document_top_domains + document_chunk_top_domains rows written for
22	//     each successfully-promoted claim's domains, so retrieval works at
23	//     the document level even before claims accumulate.
24	//
25	// What stays the same:
26	//   - Download from Supabase Storage via service-role client (private).
27	//   - PDF / XLSX / CSV / text parsing.
28	//   - Chunking + embedding + document_chunks insert (with dedup by hash).
29	//   - Direct + sweep task variants (single document + cron safety net).
30	
31	import { schedules, task, tasks } from '@trigger.dev/sdk/v3';
32	import { and, eq, inArray } from 'drizzle-orm';
33	import { createHash } from 'crypto';
34	import { writeFile, unlink } from 'node:fs/promises';
35	import { tmpdir } from 'node:os';
36	import { join } from 'node:path';
37	import { z } from 'zod';
38	import { getDirectDb } from '@oracle/db/client';
39	import {
40	  documentChunks,
41	  documents,
42	  documentTopDomains,
43	  documentChunkTopDomains,
44	  entities,
45	  extractionBatches,
46	  extractionCandidates,
47	  extractionCandidateEvidence,
48	  extractionValidationResults,
49	  jobRuns,
50	  modelRunUsageDetails,
51	  modelRuns,
52	  oracleContextPacks,
53	  settings,
54	  type OracleDb,
55	} from '@oracle/db';
56	import {
57	  OracleAIClient,
58	  buildStandardAdapters,
59	  embedMany,
60	  getOracleRoute,
61	  resolveRouteFromSettings,
62	  makeBlock,
63	  EXTRACTION_SYSTEM_PROMPT,
64	  EXTRACTION_PROMPT_VERSION,
65	  ExtractionOutputSchema,
66	  type ExtractionOutput,
67	  type OracleModelRoute,
68	  type OraclePromptPlan,
69	} from '@oracle/ai';
70	import {
71	  computeCandidateHash,
72	  executePromotion,
73	  mapLegacyDomainsToTopDomains,
74	  stageEntityProposal,
75	  validateQuote,
76	  validateSourcePointer,
77	  validateTaxonomy,
78	  AdvisoryLockBusyError,
79	  type RegistryEntity,
80	} from '@oracle/engines';
81	import { createServiceRoleClient } from '@oracle/auth/server';
82	import type { EntityType, KnowledgeDomain, TopLevelDomainId } from '@oracle/shared';
83	
84	const CHUNK_SIZE = 1500;
85	const CHUNK_OVERLAP = 150;
86	const MAX_DOCUMENT_TEXT_CHARS = 15_000;
87	const VERTEX_FILE_CACHE_MIN_BYTES = 10 * 1024 * 1024;
88	const FALLBACK_ROUTE_ID = 'vertex_gemini_2_5_flash_extraction_primary';
89	
90	// ─────────────────────────────────────────────────────────────────────────
91	// Payload schema for the single-document task
92	// ─────────────────────────────────────────────────────────────────────────
93	const SingleDocumentPayloadSchema = z.object({
94	  documentId: z.string().uuid(),
95	});
96	
97	// ─────────────────────────────────────────────────────────────────────────
98	// Shared OracleAIClient (one per worker process, direct provider adapters)
99	// ─────────────────────────────────────────────────────────────────────────
100	function buildOracleClient(): OracleAIClient {
101	  return new OracleAIClient({
102	    adapters: buildStandardAdapters(),
103	    fallbackOnError: true,
104	  });
105	}
106	
107	// ─────────────────────────────────────────────────────────────────────────
108	// Text helpers
109	// ─────────────────────────────────────────────────────────────────────────
110	
111	function chunkText(text: string, chunkSize = CHUNK_SIZE, overlap = CHUNK_OVERLAP): string[] {
112	  if (text.length <= chunkSize) return [text];
113	  const chunks: string[] = [];
114	  let start = 0;
115	  while (start < text.length) {
116	    const end = Math.min(start + chunkSize, text.length);
117	    chunks.push(text.slice(start, end));
118	    start += chunkSize - overlap;
119	    if (start >= text.length) break;
120	  }
121	  return chunks;
122	}
123	
124	async function extractTextFromPdf(buffer: Buffer): Promise<string> {
125	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
126	  const pdfParse = (await import('pdf-parse')).default as (buf: Buffer) => Promise<{ text: string }>;
127	  const result = await pdfParse(buffer);
128	  return result.text;
129	}
130	
131	async function extractTextFromXlsx(buffer: Buffer): Promise<string> {
132	  const XLSX = await import('xlsx');
133	  const workbook = XLSX.read(buffer, { type: 'buffer' });
134	  const lines: string[] = [];
135	  for (const sheetName of workbook.SheetNames) {
136	    lines.push(`[Sheet: ${sheetName}]`);
137	    const sheet = workbook.Sheets[sheetName];
138	    if (sheet) {
139	      const csv = XLSX.utils.sheet_to_csv(sheet);
140	      lines.push(csv);
141	    }
142	  }
143	  return lines.join('\n');
144	}
145	
146	// ─────────────────────────────────────────────────────────────────────────
147	// Per-document processor
148	// ─────────────────────────────────────────────────────────────────────────
149	
150	interface ProcessDocumentResult {
151	  chunksInserted: number;
152	  candidatesStaged: number;
153	  claimsPromoted: number;
154	  duplicatesAppended: number;
155	  rejections: number;
156	}
157	
158	async function processDocument(documentId: string, jobRunId: string): Promise<ProcessDocumentResult> {
159	  const db = getDirectDb();
160	  const client = buildOracleClient();
161	  const serviceSupabase = createServiceRoleClient();
162	  const outcome: ProcessDocumentResult = {
163	    chunksInserted: 0,
164	    candidatesStaged: 0,
165	    claimsPromoted: 0,
166	    duplicatesAppended: 0,
167	    rejections: 0,
168	  };
169	
170	  // 1. Load + mark processing.
171	  const [doc] = await db.select().from(documents).where(eq(documents.id, documentId)).limit(1);
172	  if (!doc) throw new Error(`Document ${documentId} not found`);
173	  if (doc.status === 'complete') {
174	    console.log(`[document-ingestion] ${documentId} already complete — skipping`);
175	    return outcome;
176	  }
177	  await db.update(documents).set({ status: 'processing' }).where(eq(documents.id, documentId));
178	
179	  const route = await resolveExtractionRoute(db);
180	  const activeTopDomainIds = await loadActiveTopDomainIds(db);
181	  const entityRegistry = await loadEntityRegistry(db);
182	
183	  // 2. Download.
184	  const { data: blob, error: downloadError } = await serviceSupabase.storage
185	    .from(doc.storageBucket)
186	    .download(doc.storagePath);
187	  if (downloadError || !blob) {
188	    throw new Error(
189	      `Storage download failed for ${doc.storagePath}: ${downloadError?.message ?? 'empty blob'}`,
190	    );
191	  }
192	  const buffer = Buffer.from(await blob.arrayBuffer());
193	  const fileBackedCachePath =
194	    route.provider === 'vertex' && buffer.length > VERTEX_FILE_CACHE_MIN_BYTES
195	      ? await materializeVertexCacheTempFile(buffer, doc.fileName)
196	      : null;
197	
198	  // 3. Parse.
199	  let rawText: string;
200	  try {
201	    if (doc.fileType === 'application/pdf') {
202	      rawText = await extractTextFromPdf(buffer);
203	    } else if (
204	      doc.fileType === 'application/vnd.ms-excel' ||
205	      doc.fileType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
206	      doc.fileType === 'text/csv'
207	    ) {
